    /// <inheritdoc />
    protected override async ValueTask<bool> RegisterGeneratedChildComponent(MapComponent child)
    {
        switch (child)
        {
            case Layer layers:
                Layers ??= [];
                if (!Layers.Contains(layers))
                {
                    Layers = [..Layers, layers];
                    ModifiedParameters[nameof(Layers)] = Layers;
                }
                
                return true;
            case GroundNavigationConstraint navigationConstraint:
                if (navigationConstraint != NavigationConstraint)
                {
                    NavigationConstraint = navigationConstraint;
                    ModifiedParameters[nameof(NavigationConstraint)] = NavigationConstraint;
                }
                
                return true;
            default:
                return await base.RegisterGeneratedChildComponent(child);
        }
    }

    /// <inheritdoc />
    protected override async ValueTask<bool> UnregisterGeneratedChildComponent(MapComponent child)
    {
        switch (child)
        {
            case Layer layers:
                Layers = Layers?.Where(l => l != layers).ToList();
                ModifiedParameters[nameof(Layers)] = Layers;
                return true;
            case GroundNavigationConstraint:
                NavigationConstraint = null;
                ModifiedParameters[nameof(NavigationConstraint)] = NavigationConstraint;
                return true;
            default:
                return await base.UnregisterGeneratedChildComponent(child);
        }
    }
    
    /// <inheritdoc />
    public override void ValidateRequiredGeneratedChildren()
    {
    
        if (Layers is not null)
        {
            foreach (Layer child in Layers)
            {
                child.ValidateRequiredGeneratedChildren();
            }
        }
        NavigationConstraint?.ValidateRequiredGeneratedChildren();
        base.ValidateRequiredGeneratedChildren();
    }
      
